-- user03 2026-02 realistic usage dataset
begin;
set local search_path to payv_app;
update users set display_name='김민수', is_active=true, updated_at=now() where user_id='2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from notification_dispatch_log where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from notification where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from fixed_expense_execution where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from fixed_expense_definition where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from transfer where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from transaction_tag where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from attachment where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from transaction where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from budget where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from tag where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from category where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
delete from asset where owner_user_id = '2d2f6732-66f8-4cca-ad96-a918fed8c439';
on conflict (category_id) do update set owner_user_id=excluded.owner_user_id, name=excluded.name, parent_id=excluded.parent_id, depth=excluded.depth, is_system=excluded.is_system, is_active=excluded.is_active, updated_at=now();
on conflict (tag_id) do update set owner_user_id=excluded.owner_user_id, name=excluded.name, is_active=excluded.is_active, updated_at=now();
on conflict (asset_id) do update set owner_user_id=excluded.owner_user_id, name=excluded.name, asset_type=excluded.asset_type, is_active=excluded.is_active, updated_at=now();
on conflict (budget_id) do update set owner_user_id=excluded.owner_user_id, target_month=excluded.target_month, amount_limit=excluded.amount_limit, category_id=excluded.category_id, memo=excluded.memo, is_active=excluded.is_active, updated_at=now();
on conflict (definition_id) do update set owner_user_id=excluded.owner_user_id, name=excluded.name, amount=excluded.amount, asset_id=excluded.asset_id, category_id_level1=excluded.category_id_level1, category_id_level2=excluded.category_id_level2, memo=excluded.memo, cycle=excluded.cycle, day_of_month=excluded.day_of_month, is_end_of_month=excluded.is_end_of_month, is_active=excluded.is_active, updated_at=now();
on conflict (transaction_id) do update set owner_user_id=excluded.owner_user_id, transaction_type=excluded.transaction_type, amount=excluded.amount, transaction_date=excluded.transaction_date, asset_id=excluded.asset_id, memo=excluded.memo, category_id_level1=excluded.category_id_level1, category_id_level2=excluded.category_id_level2, source_type=excluded.source_type, fixed_cost_template_id=excluded.fixed_cost_template_id;
on conflict (transaction_id, tag_id) do nothing;
on conflict (transfer_id) do update set owner_user_id=excluded.owner_user_id, from_asset_id=excluded.from_asset_id, to_asset_id=excluded.to_asset_id, amount=excluded.amount, transfer_date=excluded.transfer_date, memo=excluded.memo, updated_at=now();
on conflict (execution_id) do update set owner_user_id=excluded.owner_user_id, definition_name=excluded.definition_name, amount=excluded.amount, asset_id=excluded.asset_id, category_id_level1=excluded.category_id_level1, category_id_level2=excluded.category_id_level2, memo=excluded.memo, scheduled_date=excluded.scheduled_date, status=excluded.status, transaction_id=excluded.transaction_id, failure_reason=excluded.failure_reason, batch_job_execution_id=excluded.batch_job_execution_id, processed_at=excluded.processed_at, updated_at=now();
on conflict (notification_id) do update set owner_user_id=excluded.owner_user_id, notification_type=excluded.notification_type, title=excluded.title, message=excluded.message, reference_type=excluded.reference_type, reference_id=excluded.reference_id, is_read=excluded.is_read, read_at=excluded.read_at, created_at=excluded.created_at, updated_at=now();
commit;
